import classes from './TodoItems.module.css'
import TodoList from './TodoList';
import { useState } from 'react'
import * as taskService from '../services/taskService'



const TodoItems = (props,loader) => {
    const [selectedTask, setSelectedTask]=useState(null)
      const [taskAction, setTaskAction]=useState(null)

const detailsHandler = (id) =>{
        taskService.getOne(id)
        .then(taskDetails=>{
            setSelectedTask(taskDetails)
        })
    }



return (
<section className={classes['todo-items-section']}>
{selectedTask && 'Ova e test'}
{props.loading && <Spinner/>}
 <ul className={classes['list-wrapper']}>
{props.task.map(x=>  <TodoList detailsHandler={detailsHandler}  {...x}/>)}
</ul>
</section>
);
}

export default TodoItems
